1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEAR_THRESHOLD = 2;
8	
9	const COMPONENT_BASE_PREMIUM = 25;
10	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
11	const COMPONENT_BLOCK_SIZE = 3;
12	const COMPONENT_BLOCK_PREMIUM = 60;
13	
14	const NON_COMPONENT_BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	};
20	
21	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
22	
23	const basePremiumFor = (type: string): number =>
24	  isComponent(type) ? COMPONENT_BASE_PREMIUM : NON_COMPONENT_BASE_PREMIUM[type];
25	
26	type Item = { type: string; cursed?: boolean; enchantment?: number };
27	type QuoteStep = { op: "quote"; items: Item[] };
28	type Step = QuoteStep;
29	type Customer = { yearsWithMHPCO: number };
30	type Scenario = { customer: Customer; steps: Step[] };
31	
32	const groupedBasePremium = (type: string, count: number): number => {
33	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
34	    return COMPONENT_BLOCK_PREMIUM;
35	  }
36	  return count * basePremiumFor(type);
37	};
38	
39	const countByType = (items: Item[]): Map<string, number> => {
40	  const counts = new Map<string, number>();
41	  for (const item of items) {
42	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  }
44	  return counts;
45	};
46	
47	const sumBasePremiums = (items: Item[]): number =>
48	  Array.from(countByType(items)).reduce(
49	    (total, [type, count]) => total + groupedBasePremium(type, count),
50	    0,
51	  );
52	
53	const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
54	  applies ? basePremiumFor(item.type) * rate : 0;
55	
56	const isCursed = (item: Item): boolean => item.cursed === true;
57	
58	const isHighlyEnchanted = (item: Item): boolean =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
60	
61	const itemSurchargeFor = (item: Item): number =>
62	  surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE) +
63	  surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
64	
65	const sumItemSurcharges = (items: Item[]): number =>
66	  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
67	
68	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
69	  customer.yearsWithMHPCO >= LOYALTY_YEAR_THRESHOLD
70	    ? basePremium * LOYALTY_DISCOUNT_RATE
71	    : 0;
72	
73	const quotePremium = (items: Item[], customer: Customer): number => {
74	  const basePremium = sumBasePremiums(items);
75	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
76	  const insurancePremium = Math.ceil(
77	    basePremium +
78	      sumItemSurcharges(items) +
79	      firstInsuranceSurcharge -
80	      loyaltyDiscount(basePremium, customer),
81	  );
82	  return insurancePremium + PROCESSING_FEE;
83	};
84	
85	const runStep = (step: Step, customer: Customer) => ({
86	  premium: quotePremium(step.items, customer),
87	});
88	
89	export const runScenario = (scenario: Scenario): unknown => ({
90	  results: scenario.steps.map((step) => runStep(step, scenario.customer)),
91	});
